    echo "Missing local TorchTitan checkout: ${LOCAL_TORCHTITAN_DIR}" >&2
    return 1
  fi
}

require_non_primus_image() {
  if [[ "${IMAGE}" == *primus* || "${IMAGE}" == *Primus* ]]; then
    cat >&2 <<ERROR
This launcher is the direct TorchTitan path and refuses Primus runtime images.

Selected IMAGE:
  ${IMAGE}

Use a ROCm/PyTorch or TorchTitan runtime image and keep Primus as reference-only
history for this DeepSeek-V4 canary.
ERROR
    return 3
  fi
}

