  require_local_torchtitan
  if [[ ! -d "${LOCAL_TORCHTITAN_DIR}/torchtitan/models/${CANARY_TORCHTITAN_MODULE}" ]]; then
    cat >&2 <<ERROR
TorchTitan model source is not materialized yet.

Expected:
  ${LOCAL_TORCHTITAN_DIR}/torchtitan/models/${CANARY_TORCHTITAN_MODULE}

This direct launcher intentionally refuses to substitute DeepSeek-V3 16B.
Use sources/targets/${CONFIG_NAME} as the canary contract, then port
torchtitan.models.${CANARY_TORCHTITAN_MODULE} before running training.
ERROR
    return 2
