    "${LOCAL_TORCHTITAN_DIR}/torchtitan/models/${CANARY_TORCHTITAN_MODULE}/__init__.py" \
    "${LOCAL_TORCHTITAN_DIR}/torchtitan/models/${CANARY_TORCHTITAN_MODULE}/config_registry.py" \
