should_rebuild_remote_mori() {
  if [[ "${CANARY_MORI_IMPORT_MODE:-remote}" != "remote" ]]; then
    return 1
  fi

  case "${CANARY_MORI_REBUILD_REMOTE:-auto}" in
    true|1|yes|on|ON|YES|TRUE)
      return 0
      ;;
    false|0|no|off|OFF|NO|FALSE)
      return 1
      ;;
    auto)
      if [[ "${CANARY_STANDARD_EP_COMPACT_COLLECTIVE_BACKEND:-}" == "mori_native" \
        || "${CANARY_STANDARD_EP_NEEDED_WEIGHT_EXCHANGE_IMPL:-}" == "native" \
        || "${CANARY_STANDARD_EP_NEEDED_WEIGHT_EXCHANGE_TRANSPORT:-}" == "native" \
        || "${CANARY_STANDARD_EP_NEEDED_WEIGHT_EXCHANGE_TRANSPORT:-}" == mori_sdma* \
        || -n "${CANARY_MORI_ENABLE_PROFILER:-}" ]]; then
        return 0
      fi
      if ! ssh "${TARGET_HOST}" "test -f '${REMOTE_MORI_DIR}/python/mori/libmori_pybinds.so'"; then
        return 0
      fi
      return 1
      ;;
    *)
      echo "Invalid CANARY_MORI_REBUILD_REMOTE=${CANARY_MORI_REBUILD_REMOTE}; expected auto, true, or false" >&2
      exit 2
      ;;
  esac
}

rebuild_remote_mori_if_needed() {
  if ! should_rebuild_remote_mori; then
    return 0
  fi

  ssh "${TARGET_HOST}" "cd '${REMOTE_MORI_DIR}' && docker run --rm \
    --network=host \
    --ipc=host \
    --volume '${REMOTE_ROOT}:${REMOTE_ROOT}' \
    --volume '${CACHE_REMOTE}:/root/.cache' \
    --entrypoint /bin/bash \
    '${IMAGE}' -lc \"set -euo pipefail
cd '${REMOTE_MORI_DIR}'
cmake -G Ninja \
  -DUSE_ROCM=ON \
  -DCMAKE_BUILD_TYPE=Release \
  -DGPU_TARGETS=gfx950 \
  -DWARP_ACCUM_UNROLL=1 \
  -DBUILD_SHMEM_DEVICE_WRAPPER=ON \
  -DENABLE_DEBUG_PRINTF=OFF \
  -DENABLE_STANDARD_MOE_ADAPT=OFF \
  -DENABLE_PROFILER=${CANARY_MORI_ENABLE_PROFILER:-OFF} \
  -DBUILD_EXAMPLES=OFF \
  -DBUILD_BENCHMARK=OFF \
  -DBUILD_TESTS=OFF \
  -DBUILD_UMBP=OFF \
  -DWITH_MPI=OFF \
  -DBUILD_TORCH_BOOTSTRAP=OFF \
  -DBUILD_XLA_FFI_OPS=OFF \
  -DBUILD_OPS_DEVICE=OFF \
  -DMORI_MULTITHREAD_SUPPORT=OFF \
  -B build \
  -S .
cmake --build build -j \\\$(nproc)
cp -f build/src/pybind/libmori_pybinds.so python/mori/libmori_pybinds.so
cp -f build/src/application/libmori_application.so python/mori/libmori_application.so
cp -f build/src/shmem/libmori_shmem.so python/mori/libmori_shmem.so
cp -f build/src/ops/libmori_ops.so python/mori/libmori_ops.so
cp -f build/src/io/libmori_io.so python/mori/libmori_io.so
if [[ -f build/src/collective/libmori_collective.so ]]; then
  cp -f build/src/collective/libmori_collective.so python/mori/libmori_collective.so
fi
PYTHONPATH='${REMOTE_MORI_DIR}/python' LD_LIBRARY_PATH='${REMOTE_MORI_DIR}/python/mori':\\\${LD_LIBRARY_PATH:-} \
python3 - <<'PY'
import mori
import mori.cpp as cpp
print('rebuilt_mori', mori.__file__)
print('has_compact_combine', hasattr(cpp, 'launch_standard_ep_compact_combine'))
PY\""
}

stage() {
  require_local_torchtitan
  ssh "${TARGET_HOST}" "mkdir -p '${REMOTE_TORCHTITAN_DIR}' '${REMOTE_ROOT}/config' '${REMOTE_ROOT}/tools' '${LOG_DIR}' '${DUMP_FOLDER}' '${HF_HOME_REMOTE}' '${CACHE_REMOTE}' '${CANARY_MORI_JIT_CACHE_REMOTE}' '${CANARY_AITER_JIT_CACHE_REMOTE}'"
  rsync -a --exclude '.git' "${LOCAL_TORCHTITAN_DIR}/" "${TARGET_HOST}:${REMOTE_TORCHTITAN_DIR}/"
  if [[ -d "${LOCAL_PRIMUS_TURBO_DIR}/primus_turbo" ]]; then
    ssh "${TARGET_HOST}" "mkdir -p '${REMOTE_PRIMUS_TURBO_DIR}'"
    rsync -a --exclude '.git' --exclude 'build/' "${LOCAL_PRIMUS_TURBO_DIR}/" "${TARGET_HOST}:${REMOTE_PRIMUS_TURBO_DIR}/"
  fi
  if [[ "${CANARY_MORI_IMPORT_MODE:-remote}" == "remote" ]]; then
    if [[ ! -d "${LOCAL_MORI_DIR}/python/mori" ]]; then
      echo "Missing local MORI source at ${LOCAL_MORI_DIR}; set LOCAL_MORI_DIR or use CANARY_MORI_IMPORT_MODE=image" >&2
      exit 1
    fi
    ssh "${TARGET_HOST}" "mkdir -p '${REMOTE_MORI_DIR}'"
    rsync -a --delete --exclude '.git' --exclude 'build/' --exclude 'python/mori/*.so' "${LOCAL_MORI_DIR}/" "${TARGET_HOST}:${REMOTE_MORI_DIR}/"
    rebuild_remote_mori_if_needed
  fi
  rsync -a "${LOCAL_TARGET_CONFIG}" "${TARGET_HOST}:${REMOTE_TARGET_CONFIG}"
  if [[ -f "${LOCAL_TORCHTITAN_PG_PROBE}" ]]; then
    rsync -a "${LOCAL_TORCHTITAN_PG_PROBE}" "${TARGET_HOST}:${REMOTE_TORCHTITAN_PG_PROBE}"
  fi
  if [[ -d "${LOCAL_RUNTIME_PROBE_DIR}" ]]; then
    ssh "${TARGET_HOST}" "mkdir -p '${REMOTE_RUNTIME_PROBE_DIR}'"
    rsync -a "${LOCAL_RUNTIME_PROBE_DIR}/" "${TARGET_HOST}:${REMOTE_RUNTIME_PROBE_DIR}/"
  fi
  if [[ -d "${LOCAL_OPTIMIZER_PREFLIGHT_DIR}" ]]; then
    ssh "${TARGET_HOST}" "mkdir -p '${REMOTE_OPTIMIZER_PREFLIGHT_DIR}'"
    rsync -a "${LOCAL_OPTIMIZER_PREFLIGHT_DIR}/" "${TARGET_HOST}:${REMOTE_OPTIMIZER_PREFLIGHT_DIR}/"
  fi
}

