busy_gpu_processes() {
  ssh "${TARGET_HOST}" "CANARY_VISIBLE_DEVICES='${CANARY_VISIBLE_DEVICES}' bash -s" <<'REMOTE'
set -euo pipefail
if ! command -v rocm-smi >/dev/null 2>&1; then
  exit 0
fi
if [[ -z "${CANARY_VISIBLE_DEVICES}" ]]; then
  rocm-smi --showpidgpus 2>/dev/null | awk '/^PID / && $0 !~ /using 0 DRM device/ {print}'
else
  rocm-smi --showpidgpus 2>/dev/null | awk -v visible="${CANARY_VISIBLE_DEVICES}" '
    BEGIN {
      split(visible, want, ",")
      for (i in want) {
        gsub(/^[[:space:]]+|[[:space:]]+$/, "", want[i])
        if (want[i] != "") {
          target[want[i]] = 1
        }
      }
    }
    /^PID / {
      pid = $2
      if ($0 !~ /:$/) {
        next
      }
      getline
      for (i = 1; i <= NF; i++) {
        if ($i in target) {
          print pid "\tuses_visible_gpu\t" $i
        }
      }
    }'
fi
REMOTE
}

require_idle_gpus() {
  if [[ "${CANARY_REQUIRE_IDLE_GPUS}" != "true" ]]; then
    echo "CANARY_REQUIRE_IDLE_GPUS=${CANARY_REQUIRE_IDLE_GPUS}; skipping GPU occupancy guard"
    return 0
  fi

  local busy
  local scope
  scope="all GPUs"
  if [[ -n "${CANARY_VISIBLE_DEVICES}" ]]; then
    scope="visible GPUs ${CANARY_VISIBLE_DEVICES}"
  fi
  busy="$(busy_gpu_processes)"
  if [[ -n "${busy}" ]]; then
    cat >&2 <<ERROR
Refusing to start the direct ${GPUS_PER_NODE}xMI350 run/probe because active GPU processes were found on ${TARGET_HOST} (${scope}).
Set CANARY_VISIBLE_DEVICES to an idle slice or set CANARY_REQUIRE_IDLE_GPUS=false only when intentionally co-scheduling.

${busy}
ERROR
    return 1
  fi
}

