should_use_persistent_jit_cache() {
  case "${CANARY_PERSIST_JIT_CACHE}" in
    true) return 0 ;;
    false) return 1 ;;
    auto)
      [[ "${CANARY_MOE_COMM_BACKEND}" == "mori" \
        || -n "${CANARY_EXPERIMENTAL_MORI_AITER_MOE}" \
        || "${CANARY_STANDARD_EP_COMPACT_COLLECTIVE_BACKEND}" == "mori_native" \
        || "${CANARY_STANDARD_EP_NEEDED_WEIGHT_EXCHANGE_IMPL}" == "native" \
        || "${CANARY_STANDARD_EP_NEEDED_WEIGHT_EXCHANGE_TRANSPORT}" == "native" \
        || "${CANARY_STANDARD_EP_NEEDED_WEIGHT_EXCHANGE_TRANSPORT}" == mori_sdma* \
        || "${CANARY_STANDARD_EP_HOT_WEIGHT_REDUCE_BACKEND}" == "mori_sdma" \
        || "${CANARY_STANDARD_EP_HOT_WEIGHT_FORWARD_BACKEND}" == "mori_sdma" ]]
      ;;
    *)
      echo "Invalid CANARY_PERSIST_JIT_CACHE=${CANARY_PERSIST_JIT_CACHE}; expected auto, true, or false" >&2
      exit 2
      ;;
  esac
}

prepare_persistent_jit_cache() {
  if ! should_use_persistent_jit_cache; then
    return 0
  fi

  mkdir -p "${CANARY_MORI_JIT_CACHE_REMOTE}" "${CANARY_AITER_JIT_CACHE_REMOTE}"
  docker run --rm \
    --volume "${CANARY_AITER_JIT_CACHE_REMOTE}:/aiter_jit_cache" \
    --entrypoint /bin/bash \
    "${IMAGE}" -lc "set -euo pipefail
if [[ ! -d '${CANARY_AITER_JIT_CONTAINER_DIR}' ]]; then
  echo 'Missing AITER JIT package dir in image: ${CANARY_AITER_JIT_CONTAINER_DIR}' >&2
  exit 4
fi
if [[ ! -f /aiter_jit_cache/__init__.py ]]; then
  cp -a '${CANARY_AITER_JIT_CONTAINER_DIR}/.' /aiter_jit_cache/
fi"

  docker_args+=(
    --volume "${CANARY_MORI_JIT_CACHE_REMOTE}:/root/.mori/jit"
    --volume "${CANARY_AITER_JIT_CACHE_REMOTE}:${CANARY_AITER_JIT_CONTAINER_DIR}"
  )
  if [[ -n "${CANARY_MORI_ENABLE_PROFILER:-}" ]]; then
    docker_args+=(--env MORI_KERNEL_DIR=/root/.mori/jit/gfx950_mlx5_profiler/latest)
  else
    docker_args+=(--env MORI_KERNEL_DIR=/root/.mori/jit/gfx950_mlx5/latest)
  fi
}

