print_command() {
  cat <<COMMAND
python3 -m torch.distributed.run \\
  --nproc_per_node="${GPUS_PER_NODE}" \\
  --master_addr=127.0.0.1 \\
  --master_port="${MASTER_PORT}" \\
  "${REMOTE_TORCHTITAN_DIR}/torchtitan/train.py" \\
  --module "${CANARY_TORCHTITAN_MODULE}" \\
  --config "${CANARY_TORCHTITAN_CONFIG}" \\
  --dump_folder "${DUMP_FOLDER}" \\
COMMAND
  if [[ -n "${CANARY_RESUME_CHECKPOINT_PATH}" ]]; then
    cat <<COMMAND
  --checkpoint.initial_load_path "${CANARY_RESUME_CHECKPOINT_PATH}" \\
  --checkpoint.no_initial_load_model_only \\
COMMAND
  fi
  cat <<COMMAND
  --training.local_batch_size "${CANARY_MBS}" \\
  --training.global_batch_size "${CANARY_GBS}" \\
  --training.seq_len "${CANARY_SEQ_LEN}" \\
  --training.steps "${CANARY_STEPS}" \\
COMMAND
  if [[ -n "${CANARY_OPTIMIZER_IMPLEMENTATION}" ]]; then
    cat <<COMMAND
  --optimizer.implementation "${CANARY_OPTIMIZER_IMPLEMENTATION}" \\
COMMAND
  fi
  if [[ "${CANARY_ENABLE_CPU_OFFLOAD}" == "true" ]]; then
    cat <<COMMAND
  --training.enable_cpu_offload \\
COMMAND
  fi
  if [[ "${CANARY_CHECKPOINT_ENABLE}" == "false" ]]; then
    cat <<COMMAND
  --checkpoint.no-enable \\
COMMAND
  else
    cat <<COMMAND
  --checkpoint.enable \\
COMMAND
  fi
