train_cmd=(
  python3 -m torch.distributed.run
  --nproc_per_node="${GPUS_PER_NODE}"
  --master_addr=127.0.0.1
  --master_port="${MASTER_PORT}"
  "${REMOTE_TORCHTITAN_DIR}/torchtitan/train.py"
  --module "${CANARY_TORCHTITAN_MODULE}"
  --config "${CANARY_TORCHTITAN_CONFIG}"
  --dump_folder "${DUMP_FOLDER}"
  --training.local_batch_size "${CANARY_MBS}"
  --training.global_batch_size "${CANARY_GBS}"
  --training.seq_len "${CANARY_SEQ_LEN}"
  --training.steps "${CANARY_STEPS}"
  --parallelism.tensor_parallel_degree 1
  --parallelism.pipeline_parallel_degree 1
  --parallelism.context_parallel_degree 1
  --parallelism.expert_parallel_degree "${CANARY_EP}"
  --parallelism.data_parallel_shard_degree "${CANARY_DP_SHARD}"
  --activation_checkpoint.mode "${CANARY_ACTIVATION_CHECKPOINT_MODE}"
)
if [[ -n "${CANARY_OPTIMIZER_IMPLEMENTATION}" ]]; then
  train_cmd+=(--optimizer.implementation "${CANARY_OPTIMIZER_IMPLEMENTATION}")
fi
if [[ "${CANARY_ENABLE_CPU_OFFLOAD}" == "true" ]]; then
  train_cmd+=(--training.enable_cpu_offload)
fi
if [[ -n "${CANARY_DEBUG_SEED}" ]]; then
  train_cmd+=(--debug.seed "${CANARY_DEBUG_SEED}")
fi
if [[ "${CANARY_DEBUG_MOE_FORCE_LOAD_BALANCE}" == "true" ]]; then
  train_cmd+=(--debug.moe_force_load_balance)
fi
if [[ "${CANARY_ENABLE_STRUCTURED_LOGGING}" == "false" ]]; then
  train_cmd+=(--debug.no-enable-structured-logging)
fi
if [[ "${CANARY_ENABLE_PROFILING}" == "true" ]]; then
  train_cmd+=(
    --profiler.enable_profiling
    --profiler.save_traces_folder "${CANARY_PROFILER_SAVE_TRACES_FOLDER}"
    --profiler.profile_freq "${CANARY_PROFILER_PROFILE_FREQ}"
    --profiler.profiler_warmup "${CANARY_PROFILER_WARMUP}"
    --profiler.profiler_active "${CANARY_PROFILER_ACTIVE}"
  )
  if [[ -n "${CANARY_PROFILER_REPEAT}" ]]; then
    train_cmd+=(--profiler.profiler_repeat "${CANARY_PROFILER_REPEAT}")
  fi
fi
if [[ "${CANARY_CHECKPOINT_ENABLE}" == "false" ]]; then
  train_cmd+=(--checkpoint.no-enable)
else
  train_cmd+=(--checkpoint.enable)
fi
train_cmd+=(--checkpoint.interval "${CANARY_CHECKPOINT_INTERVAL}")
if [[ -n "${CANARY_RESUME_CHECKPOINT_PATH}" ]]; then
  train_cmd+=(
    --checkpoint.initial_load_path "${CANARY_RESUME_CHECKPOINT_PATH}"
    --checkpoint.no_initial_load_model_only
  )
fi
if [[ -n "${CANARY_ROCPROF_OUTPUT_DIR}" ]]; then
  rocprof_cmd=(
    rocprofv3
    --kernel-trace
    --marker-trace
    --kernel-rename
    --stats
    --output-format csv
