      ;;
  esac

  "${docker_args[@]}" -lc "cd '${REMOTE_TORCHTITAN_DIR}' && ${mori_import_prefix} && ${train_cmd_string}"
} 2>&1 | tee "${OUTER_LOG}"
REMOTE
}

run_pg_probe() {
  if [[ -z "${RUN_ID_WAS_SET}" ]]; then
    RUN_ID="torchtitan_direct_dsv4_${CANARY_CONFIG_LABEL}_bf16_${GPUS_PER_NODE}xmi350_pg_probe_${RUN_TS}"
    LOG_DIR="${REMOTE_ROOT}/logs/${RUN_ID}"
    OUTER_LOG="${LOG_DIR}/docker-run.log"
  fi

  check_source
  require_non_primus_image
  require_idle_gpus
  stage
  ssh "${TARGET_HOST}" \
    "IMAGE='${IMAGE}' REMOTE_ROOT='${REMOTE_ROOT}' REMOTE_TORCHTITAN_DIR='${REMOTE_TORCHTITAN_DIR}' REMOTE_PRIMUS_TURBO_DIR='${REMOTE_PRIMUS_TURBO_DIR}' CANARY_MORI_IMPORT_MODE='${CANARY_MORI_IMPORT_MODE}' REMOTE_TORCHTITAN_PG_PROBE='${REMOTE_TORCHTITAN_PG_PROBE}' RUN_ID='${RUN_ID}' LOG_DIR='${LOG_DIR}' OUTER_LOG='${OUTER_LOG}' MASTER_PORT='${MASTER_PORT}' GPUS_PER_NODE='${GPUS_PER_NODE}' CANARY_EP='${CANARY_EP}' CANARY_DP_SHARD='${CANARY_DP_SHARD}' CANARY_VISIBLE_DEVICES='${CANARY_VISIBLE_DEVICES}' CANARY_DEDICATED_EP_PG='${CANARY_DEDICATED_EP_PG}' TORCHTITAN_EP_BACKEND_OVERRIDE='${TORCHTITAN_EP_BACKEND_OVERRIDE}' HF_HOME_REMOTE='${HF_HOME_REMOTE}' CACHE_REMOTE='${CACHE_REMOTE}' bash -s" <<'REMOTE'
set -euo pipefail
mkdir -p "${LOG_DIR}"

docker_args=(
  docker run --rm
  --network=host
  --ipc=host
  --privileged
  --device=/dev/kfd
  --device=/dev/dri
  --cap-add=SYS_PTRACE
  --cap-add=CAP_SYS_ADMIN
  --security-opt seccomp=unconfined
  --group-add video
  --ulimit nofile=1048576:1048576
  --volume "${REMOTE_ROOT}:${REMOTE_ROOT}"
  --volume "${CACHE_REMOTE}:/root/.cache"
  --volume "${HF_HOME_REMOTE}:/root/.cache/huggingface"
  --env HF_HOME=/root/.cache/huggingface
  --env HSA_NO_SCRATCH_RECLAIM=1
  --env GPU_MAX_HW_QUEUES=2
  --entrypoint /bin/bash
)

if [[ "${CANARY_DEDICATED_EP_PG}" == "true" ]]; then
  docker_args+=(--env TORCHTITAN_DEVICE_MESH_EP_BACKEND_OVERRIDE="${TORCHTITAN_EP_BACKEND_OVERRIDE:-nccl}")
fi

if [[ -n "${CANARY_VISIBLE_DEVICES}" ]]; then
  docker_args+=(--env CUDA_VISIBLE_DEVICES="${CANARY_VISIBLE_DEVICES}")
fi
docker_args+=("${IMAGE}")

probe_cmd=(
  python3 -m torch.distributed.run
  --nproc_per_node="${GPUS_PER_NODE}"
  --master_addr=127.0.0.1
  --master_port="${MASTER_PORT}"
  "${REMOTE_TORCHTITAN_PG_PROBE}"
  --dp-replicate 1
  --dp-shard "${CANARY_DP_SHARD}"
  --cp 1
  --tp 1
  --pp 1
  --ep "${CANARY_EP}"
  --etp 1
  --backend nccl
  --output "${LOG_DIR}/torchtitan_pg_probe.json"
  --smoke-collectives
)
printf -v probe_cmd_string '%q ' "${probe_cmd[@]}"

{
  echo "run_id=${RUN_ID}"
  echo "started=$(date -Is)"
  echo "image=${IMAGE}"
  echo "torchtitan=${REMOTE_TORCHTITAN_DIR}"
  echo "probe=${REMOTE_TORCHTITAN_PG_PROBE}"
  echo "shape=TP1_PP1_CP1_FSDP${GPUS_PER_NODE}_EP${CANARY_EP}"
  echo "visible_devices=${CANARY_VISIBLE_DEVICES:-all}"
  echo "mori_import_mode=${CANARY_MORI_IMPORT_MODE:-remote}"
  echo "dedicated_ep_pg=${CANARY_DEDICATED_EP_PG}"
  echo "output=${LOG_DIR}/torchtitan_pg_probe.json"
  case "${CANARY_MORI_IMPORT_MODE:-remote}" in
    image)
      mori_import_prefix="export PYTHONPATH='${REMOTE_TORCHTITAN_DIR}:${REMOTE_PRIMUS_TURBO_DIR}'"
      ;;
    remote)
      mori_import_prefix="export PYTHONPATH='${REMOTE_TORCHTITAN_DIR}:${REMOTE_PRIMUS_TURBO_DIR}:${REMOTE_ROOT}/sources/references/mori/python' && export LD_LIBRARY_PATH='${REMOTE_ROOT}/sources/references/mori/python/mori':\${LD_LIBRARY_PATH:-}"
      ;;
    *)
      echo "invalid CANARY_MORI_IMPORT_MODE=${CANARY_MORI_IMPORT_MODE}; expected remote or image" >&2
      exit 2
      ;;
  esac

  "${docker_args[@]}" -lc "cd '${REMOTE_TORCHTITAN_DIR}' && ${mori_import_prefix} && ${probe_cmd_string}"
} 2>&1 | tee "${OUTER_LOG}"
REMOTE
}

case "${ACTION}" in
  check-source) check_source ;;
  check-config) check_config ;;
  stage) stage ;;
  print-command) print_command ;;
  run) run_direct ;;
  pg-probe) run_pg_probe ;;
  *)
    cat <<USAGE
Usage: $0 <action>

Actions:
  check-source   Require torchtitan.models.deepseek_v4 to exist locally.
  check-config   Parse the DSv4 config inside the selected non-Primus image.
  stage          Copy the selected TorchTitan checkout and DSv4 target contract.
  print-command  Print the intended direct torchrun command.
  run            Run direct TorchTitan training. Fails until DSv4 is materialized.
  pg-probe       Inspect direct-runtime FSDP/EP DeviceMesh ProcessGroup identity.

This launcher intentionally skips primus-cli and refuses Primus runtime images.
USAGE
    ;;
esac
